/**
 * Analytics route handlers — API layer for analytics dashboard.
 *
 * Since TaskFlow Pro does not use an HTTP framework, these route handlers
 * are defined as typed functions with explicit request/response shapes.
 * They follow the same pattern as the service layer: receive typed input,
 * delegate to AnalyticsService, return typed output.
 *
 * Route structure:
 *
 *   GET /api/analytics/dashboard
 *     → getDashboardHandler(query) → AnalyticsResponse<DashboardData>
 *     Full dashboard payload with all metric summaries, breakdowns,
 *     and user analytics. This is the primary endpoint for the dashboard UI.
 *
 *   GET /api/analytics/metrics/:type
 *     → getMetricHandler(query) → AnalyticsResponse<MetricSummary>
 *     Individual metric with time series. Used for drill-down views
 *     or when the frontend needs to refresh a single card.
 *
 *   GET /api/analytics/orders/status
 *     → getOrderStatusHandler(query) → AnalyticsResponse<OrderStatusBreakdown[]>
 *     Order status distribution. Separated so the frontend can poll
 *     this independently (order statuses change more frequently).
 *
 *   GET /api/analytics/revenue
 *     → getRevenueHandler(query) → AnalyticsResponse<RevenueBreakdown>
 *     Revenue breakdown by status. Useful for finance-focused views.
 *
 *   GET /api/analytics/users
 *     → getUserAnalyticsHandler(query) → AnalyticsResponse<UserAnalytics>
 *     User growth, activity, and role distribution.
 *
 * All handlers accept an AnalyticsQuery (or MetricQuery) and return an
 * AnalyticsResponse<T> wrapper. The wrapper includes generation timestamp
 * and query duration for observability.
 */

import type { AnalyticsService } from '../services/analytics.service.js';
import type {
  AnalyticsQuery,
  AnalyticsErrorResponse,
  AnalyticsResponse,
  DashboardData,
  MetricQuery,
  MetricSummary,
  MetricType,
  OrderStatusBreakdown,
  RevenueBreakdown,
  TimeGranularity,
  UserAnalytics,
} from '../models/analytics.js';

// ---------------------------------------------------------------------------
// Validation helpers
// ---------------------------------------------------------------------------

const VALID_METRIC_TYPES: MetricType[] = ['orders', 'revenue', 'users', 'average-order-value'];
const VALID_GRANULARITIES: TimeGranularity[] = ['hour', 'day', 'week', 'month'];

function isValidMetricType(value: string): value is MetricType {
  return VALID_METRIC_TYPES.includes(value as MetricType);
}

function isValidGranularity(value: string): value is TimeGranularity {
  return VALID_GRANULARITIES.includes(value as TimeGranularity);
}

/**
 * Validate an AnalyticsQuery, returning an error message if invalid or null if valid.
 */
function validateQuery(query: AnalyticsQuery): string | null {
  if (!(query.startDate instanceof Date) || isNaN(query.startDate.getTime())) {
    return 'Invalid startDate: must be a valid Date';
  }
  if (!(query.endDate instanceof Date) || isNaN(query.endDate.getTime())) {
    return 'Invalid endDate: must be a valid Date';
  }
  if (query.startDate >= query.endDate) {
    return 'Invalid date range: startDate must be before endDate';
  }
  if (query.granularity !== undefined && !isValidGranularity(query.granularity)) {
    return `Invalid granularity: "${query.granularity}". Valid values: ${VALID_GRANULARITIES.join(', ')}`;
  }
  return null;
}

// ---------------------------------------------------------------------------
// Response helpers
// ---------------------------------------------------------------------------

/**
 * Wrap a service call in the standard AnalyticsResponse envelope,
 * measuring query duration automatically.
 */
async function wrapResponse<T>(fn: () => Promise<T>): Promise<AnalyticsResponse<T>> {
  const start = Date.now();
  const data = await fn();
  return {
    success: true,
    data,
    meta: {
      generatedAt: new Date(),
      queryDurationMs: Date.now() - start,
    },
  };
}

/**
 * Build a standardized error response.
 */
function errorResponse(message: string, startTime: number): AnalyticsErrorResponse {
  return {
    success: false,
    error: message,
    meta: {
      generatedAt: new Date(),
      queryDurationMs: Date.now() - startTime,
    },
  };
}

// ---------------------------------------------------------------------------
// Route handler factory
// ---------------------------------------------------------------------------

/**
 * Creates all analytics route handlers, bound to a given AnalyticsService.
 *
 * Usage:
 *   const analyticsService = new AnalyticsService(orderRepo, userRepo);
 *   const routes = createAnalyticsRoutes(analyticsService);
 *   const dashboard = await routes.getDashboard({ startDate, endDate });
 */
export function createAnalyticsRoutes(service: AnalyticsService) {
  return {
    /**
     * GET /api/analytics/dashboard
     *
     * Returns the full dashboard payload.
     */
    async getDashboard(
      query: AnalyticsQuery,
    ): Promise<AnalyticsResponse<DashboardData> | AnalyticsErrorResponse> {
      const start = Date.now();
      const validationError = validateQuery(query);
      if (validationError) {
        return errorResponse(validationError, start);
      }

      try {
        return await wrapResponse(() => service.getDashboard(query));
      } catch (err) {
        const message = err instanceof Error ? err.message : 'Internal server error';
        return errorResponse(message, start);
      }
    },

    /**
     * GET /api/analytics/metrics/:type
     *
     * Returns a single metric summary with time series.
     * @param metricType - one of: orders, revenue, users, average-order-value
     */
    async getMetric(
      metricType: string,
      query: AnalyticsQuery,
    ): Promise<AnalyticsResponse<MetricSummary> | AnalyticsErrorResponse> {
      const start = Date.now();

      if (!isValidMetricType(metricType)) {
        return errorResponse(
          `Invalid metric type: "${metricType}". Valid types: ${VALID_METRIC_TYPES.join(', ')}`,
          start,
        );
      }

      const validationError = validateQuery(query);
      if (validationError) {
        return errorResponse(validationError, start);
      }

      try {
        const metricQuery: MetricQuery = { ...query, metricType };
        return await wrapResponse(() => service.getMetricSummary(metricQuery));
      } catch (err) {
        const message = err instanceof Error ? err.message : 'Internal server error';
        return errorResponse(message, start);
      }
    },

    /**
     * GET /api/analytics/orders/status
     *
     * Returns order status distribution.
     */
    async getOrderStatus(
      query: AnalyticsQuery,
    ): Promise<AnalyticsResponse<OrderStatusBreakdown[]> | AnalyticsErrorResponse> {
      const start = Date.now();
      const validationError = validateQuery(query);
      if (validationError) {
        return errorResponse(validationError, start);
      }

      try {
        return await wrapResponse(() => service.getOrderStatusBreakdown(query));
      } catch (err) {
        const message = err instanceof Error ? err.message : 'Internal server error';
        return errorResponse(message, start);
      }
    },

    /**
     * GET /api/analytics/revenue
     *
     * Returns revenue breakdown.
     */
    async getRevenue(
      query: AnalyticsQuery,
    ): Promise<AnalyticsResponse<RevenueBreakdown> | AnalyticsErrorResponse> {
      const start = Date.now();
      const validationError = validateQuery(query);
      if (validationError) {
        return errorResponse(validationError, start);
      }

      try {
        return await wrapResponse(() => service.getRevenueBreakdown(query));
      } catch (err) {
        const message = err instanceof Error ? err.message : 'Internal server error';
        return errorResponse(message, start);
      }
    },

    /**
     * GET /api/analytics/users
     *
     * Returns user analytics.
     */
    async getUserAnalytics(
      query: AnalyticsQuery,
    ): Promise<AnalyticsResponse<UserAnalytics> | AnalyticsErrorResponse> {
      const start = Date.now();
      const validationError = validateQuery(query);
      if (validationError) {
        return errorResponse(validationError, start);
      }

      try {
        return await wrapResponse(() => service.getUserAnalytics(query));
      } catch (err) {
        const message = err instanceof Error ? err.message : 'Internal server error';
        return errorResponse(message, start);
      }
    },
  };
}

/**
 * Type of the route handler object returned by createAnalyticsRoutes.
 * Useful for consumers that need to reference the handler signatures.
 */
export type AnalyticsRoutes = ReturnType<typeof createAnalyticsRoutes>;

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import { createAnalyticsRoutes } from '../../src/routes/analytics.routes.js';
import type { AnalyticsQuery } from '../../src/models/analytics.js';
import type { User } from '../../src/models/user.js';
import type { Order } from '../../src/models/order.js';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function makeUser(overrides: Partial<User> & { id: string }): User {
  return {
    name: 'Test User',
    email: `${overrides.id}@example.com`,
    role: 'member',
    createdAt: new Date('2025-01-15'),
    updatedAt: new Date('2025-01-15'),
    ...overrides,
  };
}

function makeOrder(overrides: Partial<Order> & { id: string; userId: string }): Order {
  return {
    items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 100 }],
    total: 100,
    status: 'pending',
    createdAt: new Date('2025-02-01'),
    updatedAt: new Date('2025-02-01'),
    ...overrides,
  };
}

describe('Analytics Routes', () => {
  let db: Database;
  let userRepo: UserRepository;
  let orderRepo: OrderRepository;
  let service: AnalyticsService;
  let routes: ReturnType<typeof createAnalyticsRoutes>;

  const febQuery: AnalyticsQuery = {
    startDate: new Date('2025-02-01'),
    endDate: new Date('2025-02-28T23:59:59.999Z'),
    granularity: 'day',
  };

  beforeEach(() => {
    db = new Database();
    userRepo = new UserRepository(db);
    orderRepo = new OrderRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
    routes = createAnalyticsRoutes(service);
  });

  // -------------------------------------------------------------------------
  // Input validation
  // -------------------------------------------------------------------------

  describe('input validation', () => {
    it('should reject invalid startDate', async () => {
      const result = await routes.getDashboard({
        startDate: new Date('invalid'),
        endDate: new Date('2025-02-28'),
      });

      expect(result.success).toBe(false);
      expect('error' in result && result.error).toContain('Invalid startDate');
    });

    it('should reject invalid endDate', async () => {
      const result = await routes.getDashboard({
        startDate: new Date('2025-02-01'),
        endDate: new Date('invalid'),
      });

      expect(result.success).toBe(false);
      expect('error' in result && result.error).toContain('Invalid endDate');
    });

    it('should reject startDate >= endDate', async () => {
      const result = await routes.getDashboard({
        startDate: new Date('2025-02-28'),
        endDate: new Date('2025-02-01'),
      });

      expect(result.success).toBe(false);
      expect('error' in result && result.error).toContain('startDate must be before endDate');
    });

    it('should reject equal startDate and endDate', async () => {
      const date = new Date('2025-02-15');
      const result = await routes.getDashboard({
        startDate: date,
        endDate: date,
      });

      expect(result.success).toBe(false);
      expect('error' in result && result.error).toContain('startDate must be before endDate');
    });

    it('should reject invalid granularity', async () => {
      const result = await routes.getDashboard({
        startDate: new Date('2025-02-01'),
        endDate: new Date('2025-02-28'),
        granularity: 'yearly' as any,
      });

      expect(result.success).toBe(false);
      expect('error' in result && result.error).toContain('Invalid granularity');
    });

    it('should accept valid granularity values', async () => {
      for (const granularity of ['hour', 'day', 'week', 'month'] as const) {
        const result = await routes.getDashboard({
          startDate: new Date('2025-02-01'),
          endDate: new Date('2025-02-28'),
          granularity,
        });
        expect(result.success).toBe(true);
      }
    });

    it('should reject invalid metric type', async () => {
      const result = await routes.getMetric('invalid-metric', febQuery);

      expect(result.success).toBe(false);
      expect('error' in result && result.error).toContain('Invalid metric type');
    });

    it('should validate query in getMetric even with valid metric type', async () => {
      const result = await routes.getMetric('orders', {
        startDate: new Date('invalid'),
        endDate: new Date('2025-02-28'),
      });

      expect(result.success).toBe(false);
      expect('error' in result && result.error).toContain('Invalid startDate');
    });

    it('should validate query in getOrderStatus', async () => {
      const result = await routes.getOrderStatus({
        startDate: new Date('2025-03-01'),
        endDate: new Date('2025-02-01'),
      });

      expect(result.success).toBe(false);
      expect('error' in result && result.error).toContain('startDate must be before endDate');
    });

    it('should validate query in getRevenue', async () => {
      const result = await routes.getRevenue({
        startDate: new Date('invalid'),
        endDate: new Date('2025-02-28'),
      });

      expect(result.success).toBe(false);
      expect('error' in result && result.error).toContain('Invalid startDate');
    });

    it('should validate query in getUserAnalytics', async () => {
      const result = await routes.getUserAnalytics({
        startDate: new Date('2025-03-01'),
        endDate: new Date('2025-02-01'),
      });

      expect(result.success).toBe(false);
      expect('error' in result && result.error).toContain('startDate must be before endDate');
    });
  });

  // -------------------------------------------------------------------------
  // Successful responses
  // -------------------------------------------------------------------------

  describe('getDashboard', () => {
    it('should return dashboard data with correct response shape', async () => {
      userRepo.save(makeUser({ id: 'u1', createdAt: new Date('2025-02-01') }));
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 100, createdAt: new Date('2025-02-05') }));

      const result = await routes.getDashboard(febQuery);

      expect(result.success).toBe(true);
      expect(result.meta.generatedAt).toBeInstanceOf(Date);
      expect(result.meta.queryDurationMs).toBeGreaterThanOrEqual(0);

      if (result.success) {
        expect(result.data.metrics.orders.currentValue).toBe(1);
        expect(result.data.metrics.revenue.currentValue).toBe(100);
        expect(result.data.orderStatusBreakdown).toHaveLength(5);
        expect(result.data.revenueBreakdown.totalRevenue).toBe(100);
        expect(result.data.userAnalytics.totalUsers).toBe(1);
        expect(result.data.generatedAt).toBeInstanceOf(Date);
      }
    });
  });

  describe('getMetric', () => {
    it('should return metric summary for valid metric types', async () => {
      userRepo.save(makeUser({ id: 'u1' }));
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 50, createdAt: new Date('2025-02-05') }));

      for (const type of ['orders', 'revenue', 'users', 'average-order-value']) {
        const result = await routes.getMetric(type, febQuery);
        expect(result.success).toBe(true);
        if (result.success) {
          expect(result.data.metricType).toBe(type);
          expect(result.data.timeSeries).toBeDefined();
        }
      }
    });

    it('should return correct metric values', async () => {
      userRepo.save(makeUser({ id: 'u1' }));
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 100, createdAt: new Date('2025-02-05') }));
      orderRepo.save(makeOrder({ id: 'o2', userId: 'u1', total: 200, createdAt: new Date('2025-02-10') }));

      const result = await routes.getMetric('revenue', febQuery);

      expect(result.success).toBe(true);
      if (result.success) {
        expect(result.data.currentValue).toBe(300);
      }
    });
  });

  describe('getOrderStatus', () => {
    it('should return order status breakdown', async () => {
      userRepo.save(makeUser({ id: 'u1' }));
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', status: 'pending', createdAt: new Date('2025-02-05') }));
      orderRepo.save(makeOrder({ id: 'o2', userId: 'u1', status: 'delivered', createdAt: new Date('2025-02-06') }));

      const result = await routes.getOrderStatus(febQuery);

      expect(result.success).toBe(true);
      if (result.success) {
        expect(result.data).toHaveLength(5);
        const pending = result.data.find((d) => d.status === 'pending')!;
        expect(pending.count).toBe(1);
        expect(pending.percentage).toBe(50);
      }
    });
  });

  describe('getRevenue', () => {
    it('should return revenue breakdown', async () => {
      userRepo.save(makeUser({ id: 'u1' }));
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 150, createdAt: new Date('2025-02-05') }));

      const result = await routes.getRevenue(febQuery);

      expect(result.success).toBe(true);
      if (result.success) {
        expect(result.data.totalRevenue).toBe(150);
        expect(result.data.averageOrderValue).toBe(150);
        expect(result.data.byStatus).toHaveLength(5);
      }
    });
  });

  describe('getUserAnalytics', () => {
    it('should return user analytics', async () => {
      userRepo.save(makeUser({ id: 'u1', role: 'admin', createdAt: new Date('2025-02-01') }));
      userRepo.save(makeUser({ id: 'u2', role: 'member', createdAt: new Date('2025-02-10') }));
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', createdAt: new Date('2025-02-05') }));

      const result = await routes.getUserAnalytics(febQuery);

      expect(result.success).toBe(true);
      if (result.success) {
        expect(result.data.totalUsers).toBe(2);
        expect(result.data.newUsersInPeriod).toBe(2);
        expect(result.data.activeUsersInPeriod).toBe(1);
        expect(result.data.byRole).toHaveLength(2);
      }
    });
  });

  // -------------------------------------------------------------------------
  // Error response shape
  // -------------------------------------------------------------------------

  describe('error response shape', () => {
    it('should include meta with generatedAt and queryDurationMs on error', async () => {
      const result = await routes.getDashboard({
        startDate: new Date('invalid'),
        endDate: new Date('2025-02-28'),
      });

      expect(result.success).toBe(false);
      expect(result.meta.generatedAt).toBeInstanceOf(Date);
      expect(result.meta.queryDurationMs).toBeGreaterThanOrEqual(0);
    });

    it('should not include data property on error', async () => {
      const result = await routes.getMetric('bad', febQuery);

      expect(result.success).toBe(false);
      expect('data' in result).toBe(false);
      expect('error' in result).toBe(true);
    });
  });
});

